111:   always @ (posedge clk_i or negedge rst_ni)
112:     begin: save_inputs
113:       if (!rst_ni)
114:         begin
115:           //start_d <= 'b0;
116:           start_d <= 'b0 ; 
117:           length_d <= 'b0 ;
118:           source_addr_lsb_d <= 'b0 ; 
119:           source_addr_msb_d <= 'b0 ; 
120:           dest_addr_lsb_d <= 'b0 ; 
121:           dest_addr_msb_d <= 'b0 ; 
122:         end
123:       else 
124:         begin
125:           if (dma_ctrl_reg == CTRL_IDLE || dma_ctrl_reg == CTRL_DONE) 
